import{_ as l,c as r,o as t,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.33：新增 GitLab Duo 支持，改善项目体验","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.33.md","filePath":"changelog/v1.1.33.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.33.md"};function h(n,e,d,s,c,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-33-新增-gitlab-duo-支持-改善项目体验" tabindex="-1">v1.1.33：新增 GitLab Duo 支持，改善项目体验 <a class="header-anchor" href="#v1-1-33-新增-gitlab-duo-支持-改善项目体验" aria-label="Permalink to “v1.1.33：新增 GitLab Duo 支持，改善项目体验”">​</a></h1><p><strong>发布日期</strong>：2026年01月23日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新为 Google Vertex Anthropic 添加了思考预设，支持了 GitLab Duo 模型，并改善了项目的添加、重命名等体验。</p><hr><h2 id="新功能-gitlab-duo-模型支持" tabindex="-1">新功能：GitLab Duo 模型支持 <a class="header-anchor" href="#新功能-gitlab-duo-模型支持" aria-label="Permalink to “新功能：GitLab Duo 模型支持”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>OpenCode 现在支持 <strong>GitLab Duo</strong> 模型了！GitLab Duo 是基于 OpenAI 的 AI 编程助手，可以在 GitLab 环境中提供代码补全、代码生成等功能。</p><h3 id="gitlab-duo-是什么" tabindex="-1">GitLab Duo 是什么？ <a class="header-anchor" href="#gitlab-duo-是什么" aria-label="Permalink to “GitLab Duo 是什么？”">​</a></h3><p>GitLab Duo 是 GitLab 提供的 AI 辅助编程服务，可以帮助开发者：</p><ul><li>生成代码</li><li>解释代码</li><li>代码审查</li><li>优化代码</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开 <strong>Settings</strong> (设置)</li><li>找到 <strong>Model</strong> (模型设置)</li><li>选择或配置 GitLab Duo 提供商</li><li>输入你的 API 密钥</li><li>开始使用！</li></ol><hr><h2 id="功能改进-google-vertex-anthropic-思考预设" tabindex="-1">功能改进：Google Vertex Anthropic 思考预设 <a class="header-anchor" href="#功能改进-google-vertex-anthropic-思考预设" aria-label="Permalink to “功能改进：Google Vertex Anthropic 思考预设”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 Google Vertex 的 Anthropic 提供商添加了<strong>思考预设</strong>（thinking presets）。</p><h3 id="这有什么用" tabindex="-1">这有什么用？ <a class="header-anchor" href="#这有什么用" aria-label="Permalink to “这有什么用？”">​</a></h3><p>思考预设可以让 Claude 模型：</p><ul><li>在复杂任务中先&quot;思考&quot;再输出</li><li>更好地分解问题和规划解决方案</li><li>提高代码生成的准确性</li></ul><h3 id="如何启用" tabindex="-1">如何启用？ <a class="header-anchor" href="#如何启用" aria-label="Permalink to “如何启用？”">​</a></h3><p>在使用 Google Vertex Anthropic 模型时，思考预设会自动应用，无需手动配置。</p><hr><h2 id="体验改进-项目添加和重命名" tabindex="-1">体验改进：项目添加和重命名 <a class="header-anchor" href="#体验改进-项目添加和重命名" aria-label="Permalink to “体验改进：项目添加和重命名”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><ul><li>只能从特定深度的目录添加项目</li><li>无法添加根目录的项目</li><li>非 git 项目无法重命名</li></ul><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在你可以：</p><ul><li>从任意目录深度的文件夹添加项目</li><li>直接从根目录添加项目</li><li>重命名非 git 仓库项目</li><li>项目图标颜色闪烁问题已修复</li></ul><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p><strong>添加项目</strong>：</p><ol><li>点击 <strong>Add Project</strong></li><li>浏览任意深度的文件夹</li><li>选择要添加的项目</li></ol><p><strong>重命名项目</strong>（仅非 git 项目）：</p><ol><li>在项目列表中右键点击项目</li><li>选择 <strong>Rename</strong> (重命名)</li><li>输入新名称</li></ol><hr><h2 id="体验改进-文件夹补全更完整" tabindex="-1">体验改进：文件夹补全更完整 <a class="header-anchor" href="#体验改进-文件夹补全更完整" aria-label="Permalink to “体验改进：文件夹补全更完整”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>修复了文件夹补全功能中缺少路径最后一部分的问题。</p><h3 id="这有什么好处" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>在输入路径时，自动补全会显示完整的文件夹名称，更方便你选择目标文件夹。</p><hr><h2 id="体验改进-补全优先级优化" tabindex="-1">体验改进：补全优先级优化 <a class="header-anchor" href="#体验改进-补全优先级优化" aria-label="Permalink to “体验改进：补全优先级优化”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 TUI 中为模糊搜索添加了权重，保持标题优先级。</p><h3 id="这有什么好处-1" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-1" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>搜索时，匹配标题的结果会排在更靠前的位置，让你更快找到需要的内容。</p><hr><h2 id="新功能-在权限界面显示文件路径" tabindex="-1">新功能：在权限界面显示文件路径 <a class="header-anchor" href="#新功能-在权限界面显示文件路径" aria-label="Permalink to “新功能：在权限界面显示文件路径”">​</a></h2><h3 id="这次更新了什么-4" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-4" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 <code>apply_patch</code> 请求的权限界面中，现在会显示文件路径。</p><h3 id="这有什么好处-2" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-2" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>当 AI 请求修改文件时，你可以清楚地看到将要修改哪个文件，更安全地授权操作。</p><hr><h2 id="新功能-显示应用版本" tabindex="-1">新功能：显示应用版本 <a class="header-anchor" href="#新功能-显示应用版本" aria-label="Permalink to “新功能：显示应用版本”">​</a></h2><h3 id="这次更新了什么-5" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-5" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在设置界面中添加了应用版本显示。</p><h3 id="如何查看" tabindex="-1">如何查看？ <a class="header-anchor" href="#如何查看" aria-label="Permalink to “如何查看？”">​</a></h3><ol><li>打开 <strong>Settings</strong> (设置)</li><li>查看界面底部或关于部分</li><li>可以看到当前运行的 OpenCode 版本号</li></ol><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 GitLab</td><td>✅ <strong>推荐升级</strong> (支持 Duo 模型)</td></tr><tr><td>使用 Google Vertex Anthropic</td><td>✅ 推荐升级 (思考预设)</td></tr><tr><td>经常添加/管理项目</td><td>✅ 推荐升级 (体验改善)</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',63),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add thinking presets for Google Vertex Anthropic provider (@zerone0x)</li><li>Added support for OpenAI-based GitLab Duo models (@vglafirov)</li><li>Show file path in apply_patch request permission screen (@iltenahmet)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add weight to fuzzy search to maintain title priority in TUI (@IdrisGit)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Session shouldn&#39;t be keyed</li><li>Flash of fallback icon for projects fixed</li><li>Fix project icon color flash on load</li><li>Fixed folder suggestions missing last part in path completion</li><li>Allow adding projects from any directory depth</li><li>Allow adding projects from root directory in the app</li><li>Non-git projects can now be renamed</li><li>Add app version display to settings (@alexyaroshuk)</li></ul><p><strong>Thank you to 5 community contributors:</strong></p><ul><li>@iltenahmet: <ul><li>fix(ui): show file path in apply_patch request permission screen (#10079)</li></ul></li><li>@alexyaroshuk: <ul><li>feat(app): add app version display to settings (#10095)</li></ul></li><li>@IdrisGit: <ul><li>fix(tui): add weight to fuzzy search to maintain title priority (#10106)</li></ul></li><li>@vglafirov: <ul><li>feat(gitlab): Added support for OpenAI based GitLab Duo models (#10108)</li></ul></li><li>@zerone0x: <ul><li>fix(provider): add thinking presets for Google Vertex Anthropic (#9953)</li></ul></li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=l(o,[["render",h]]);export{u as __pageData,g as default};
